using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Payments.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly PaymentGateway _sut = new();

    #region ChargeAsync — Valid Inputs

    [TestMethod]
    [DataRow("tok_valid", 100.00, DisplayName = "Standard charge")]
    [DataRow("tok_abc123", 0.01, DisplayName = "Minimum positive amount")]
    [DataRow("tok_xyz", 9999.99, DisplayName = "Large amount")]
    [DataRow("tok_special-chars_!", 50.50, DisplayName = "Token with special characters")]
    public async Task ChargeAsync_ValidInput_ThrowsNotImplementedException(
        string cardToken, double amount)
    {
        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, (decimal)amount));
    }

    #endregion

    #region ChargeAsync — Null / Empty Card Token

    [TestMethod]
    [DataRow(null, 10.00, DisplayName = "Null card token")]
    [DataRow("", 10.00, DisplayName = "Empty card token")]
    [DataRow("   ", 10.00, DisplayName = "Whitespace card token")]
    public async Task ChargeAsync_NullOrEmptyCardToken_ThrowsNotImplementedException(
        string? cardToken, double amount)
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken!, (decimal)amount));
    }

    #endregion

    #region ChargeAsync — Invalid Amount

    [TestMethod]
    [DataRow("tok_valid", 0.00, DisplayName = "Zero amount")]
    [DataRow("tok_valid", -1.00, DisplayName = "Negative amount")]
    [DataRow("tok_valid", -999.99, DisplayName = "Large negative amount")]
    public async Task ChargeAsync_InvalidAmount_ThrowsNotImplementedException(
        string cardToken, double amount)
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, (decimal)amount));
    }

    #endregion

    #region RefundAsync — Valid Charge ID

    [TestMethod]
    [DataRow("ch_valid123", DisplayName = "Standard charge ID")]
    [DataRow("ch_abc", DisplayName = "Short charge ID")]
    [DataRow("ch_long_id_value_0123456789", DisplayName = "Long charge ID")]
    public async Task RefundAsync_ValidChargeId_ThrowsNotImplementedException(
        string chargeId)
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId));
    }

    #endregion

    #region RefundAsync — Null / Empty Charge ID

    [TestMethod]
    [DataRow(null, DisplayName = "Null charge ID")]
    [DataRow("", DisplayName = "Empty charge ID")]
    [DataRow("   ", DisplayName = "Whitespace charge ID")]
    public async Task RefundAsync_NullOrEmptyChargeId_ThrowsNotImplementedException(
        string? chargeId)
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId!));
    }

    #endregion
}

